PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (YEAR(?foundingDate) AS ?foundingYear)
WHERE {
  ?iranCity wdt:P31 wd:Q515 ;
            wdt:P17 wd:Q165 ;
            wdt:P1128 24 .
  ?iranCity wdt:P6250 ?sisterCity .
  ?sisterCity wdt:P31 wd:Q515 ;
             wdt:P17 ?country .
